import json
import os
import subprocess
import tempfile
import pytest

AC_UID = "ac2_cas_conflict_exit3_no_append"
AC_TYPE = "data"


def test_AC2():
    """
    GIVEN: logs/lifecycle.jsonl has one entry for agent dev with new_score=50
    WHEN:  bash scripts/score-update.sh --agent dev --event close_success_qa_pass --expected-prev-score 99 is invoked (wrong expected score)
    THEN:  exit code is 3, logs/lifecycle.jsonl has same number of lines as before, no new entry appended
    """
    repo = "/dev/shm/dev-workspace/dot-claude"
    fd, tmp_lifecycle = tempfile.mkstemp(suffix=".jsonl", prefix="test-ac2-")
    try:
        seed = {
            "ts": "2026-05-25T00:00:00Z", "agent": "dev", "event": "score_baseline_import",
            "prev_score": 50, "new_score": 50, "delta": 0, "unclamped_score": 50,
            "actor": "migration", "reason": "seed"
        }
        with os.fdopen(fd, "w") as f:
            f.write(json.dumps(seed) + "\n")

        with open(tmp_lifecycle) as f:
            before_count = len([l for l in f if l.strip()])

        result = subprocess.run(
            ["bash", "scripts/score-update.sh",
             "--agent", "dev", "--event", "close_success_qa_pass",
             "--expected-prev-score", "99",
             "--lifecycle-file", tmp_lifecycle],
            capture_output=True, text=True, cwd=repo,
        )
        assert result.returncode == 3, (
            f"Expected exit code 3 (CAS conflict), got {result.returncode}; stderr: {result.stderr}"
        )

        with open(tmp_lifecycle) as f:
            after_count = len([l for l in f if l.strip()])
        assert after_count == before_count, (
            f"Expected {before_count} lines after CAS conflict, got {after_count}"
        )
    finally:
        try:
            os.unlink(tmp_lifecycle)
        except OSError:
            pass
